INSERT INTO meal_history (user_id, delishies_id, eaten_at, meal_type) SELECT u.id, d.id, NOW() - INTERVAL '2 days', 'LUNCH' FROM users u, delishies d WHERE u.email = 'alice@foodiseasy.ru' AND d.title = 'Борщ классический';
