INSERT INTO meal_plans (name, user_id, start_date, end_date, scope) SELECT 'Неделя Алисы', u.id, CURRENT_DATE, CURRENT_DATE + 6, 'PERSONAL' FROM users u WHERE u.email = 'alice@foodiseasy.ru' AND NOT EXISTS (SELECT 1 FROM meal_plans WHERE name = 'Неделя Алисы');
INSERT INTO meal_plan_entries (meal_plan_id, plan_date, meal_type, delishies_id) SELECT mp.id, CURRENT_DATE, 'LUNCH', d.id FROM meal_plans mp, delishies d WHERE mp.name = 'Неделя Алисы' AND d.title = 'Борщ классический' AND NOT EXISTS (SELECT 1 FROM meal_plan_entries e JOIN meal_plans p ON e.meal_plan_id = p.id WHERE p.name = 'Неделя Алисы' AND e.plan_date = CURRENT_DATE AND e.meal_type = 'LUNCH' AND e.delishies_id = d.id);
INSERT INTO meal_plan_entries (meal_plan_id, plan_date, meal_type, delishies_id) SELECT mp.id, CURRENT_DATE, 'LUNCH', d.id FROM meal_plans mp, delishies d WHERE mp.name = 'Неделя Алисы' AND d.title = 'Плов узбекский' AND NOT EXISTS (SELECT 1 FROM meal_plan_entries e JOIN meal_plans p ON e.meal_plan_id = p.id WHERE p.name = 'Неделя Алисы' AND e.plan_date = CURRENT_DATE AND e.meal_type = 'LUNCH' AND e.delishies_id = d.id);
INSERT INTO meal_plan_entries (meal_plan_id, plan_date, meal_type, delishies_id) SELECT mp.id, CURRENT_DATE, 'LUNCH', d.id FROM meal_plans mp, delishies d WHERE mp.name = 'Неделя Алисы' AND d.title = 'Греческий салат' AND NOT EXISTS (SELECT 1 FROM meal_plan_entries e JOIN meal_plans p ON e.meal_plan_id = p.id WHERE p.name = 'Неделя Алисы' AND e.plan_date = CURRENT_DATE AND e.meal_type = 'LUNCH' AND e.delishies_id = d.id);
INSERT INTO meal_plan_entries (meal_plan_id, plan_date, meal_type, delishies_id) SELECT mp.id, CURRENT_DATE, 'BREAKFAST', d.id FROM meal_plans mp, delishies d WHERE mp.name = 'Неделя Алисы' AND d.title = 'Сырники' AND NOT EXISTS (SELECT 1 FROM meal_plan_entries e JOIN meal_plans p ON e.meal_plan_id = p.id WHERE p.name = 'Неделя Алисы' AND e.plan_date = CURRENT_DATE AND e.meal_type = 'BREAKFAST' AND e.delishies_id = d.id);
INSERT INTO meal_plan_entries (meal_plan_id, plan_date, meal_type, delishies_id) SELECT mp.id, CURRENT_DATE, 'DINNER', d.id FROM meal_plans mp, delishies d WHERE mp.name = 'Неделя Алисы' AND d.title = 'Лосось на гриле' AND NOT EXISTS (SELECT 1 FROM meal_plan_entries e JOIN meal_plans p ON e.meal_plan_id = p.id WHERE p.name = 'Неделя Алисы' AND e.plan_date = CURRENT_DATE AND e.meal_type = 'DINNER' AND e.delishies_id = d.id);
INSERT INTO group_votes (group_id, title, status, created_by) SELECT g.id, 'Ужин в пятницу', 'OPEN', u.id FROM groups g, users u WHERE g.name = 'Офис FitLunch' AND u.email = 'bob@foodiseasy.ru' AND NOT EXISTS (SELECT 1 FROM group_votes WHERE title = 'Ужин в пятницу');
INSERT INTO group_vote_options (vote_id, delishies_id) SELECT v.id, d.id FROM group_votes v, delishies d WHERE v.title = 'Ужин в пятницу' AND d.title = 'Лосось на гриле' ON CONFLICT (vote_id, delishies_id) DO NOTHING;
INSERT INTO group_vote_options (vote_id, delishies_id) SELECT v.id, d.id FROM group_votes v, delishies d WHERE v.title = 'Ужин в пятницу' AND d.title = 'Кебаб из баранины' ON CONFLICT (vote_id, delishies_id) DO NOTHING;
INSERT INTO group_vote_options (vote_id, delishies_id) SELECT v.id, d.id FROM group_votes v, delishies d WHERE v.title = 'Ужин в пятницу' AND d.title = 'Рататуй' ON CONFLICT (vote_id, delishies_id) DO NOTHING;
INSERT INTO group_vote_ballots (vote_id, user_id, option_id) SELECT v.id, u.id, o.id FROM group_votes v, users u, group_vote_options o, delishies d WHERE v.title = 'Ужин в пятницу' AND u.email = 'carol@foodiseasy.ru' AND d.title = 'Лосось на гриле' AND o.vote_id = v.id AND o.delishies_id = d.id ON CONFLICT (vote_id, user_id) DO NOTHING;
